from datetime import date, timedelta

# Find the earliest Friday the 13th from 0001-01-01 (proleptic Gregorian)
d = date(1, 1, 13)  # start checking the 13th of each month
found = None
year, month = 1, 1
while year <= 1:
    try:
        d = date(year, month, 13)
        if d.weekday() == 4:  # Friday
            found = d
            break
    except ValueError:
        pass
    month += 1
    if month > 12:
        month = 1
        year += 1

if not found:
    # broader search
    for y in range(1, 401):
        for m in range(1, 13):
            d = date(y, m, 13)
            if d.weekday() == 4:
                found = d
                break
        if found:
            break

print(f'Earliest Friday the 13th: {found} ({found.strftime(\"%A, %B %d, %Y\")})')

# Count Friday the 13ths in a full 400-year cycle (years 1-400)
count = 0
for y in range(1, 401):
    for m in range(1, 13):
        if date(y, m, 13).weekday() == 4:
            count += 1

print(f'Friday the 13ths in a 400-year cycle: {count}')
print(f'Average per year: {count/400:.4f}')
print(f'Average per month: {count/(400*12):.6f}')

# Show the first few
print('\nFirst 10 Friday the 13ths:')
n = 0
for y in range(1, 401):
    for m in range(1, 13):
        d = date(y, m, 13)
        if d.weekday() == 4:
            n += 1
            if n <= 10:
                print(f'  {d}')
    if n >= 10:
        break
"

